func handleProxy(ctx context.Context, _ proxy.DecryptFn, conn net.Conn, out *proxy.ProxyDialer, connId string, _ *anypb.Any, _ proxy.RecordingManager, controlCtx ...context.Context) (proxy.ProxyConnFn, error) {
    dataCtx := ctx
    var ctrlCtx context.Context = ctx
    if len(controlCtx) > 0 {
        ctrlCtx = controlCtx[0]
    }
    const op = "tcp.HandleProxy"
    switch {
    case conn == nil:
        return nil, errors.New(dataCtx, errors.InvalidParameter, op, "conn is nil")
    case out == nil:
        return nil, errors.New(dataCtx, errors.InvalidParameter, op, "proxy dialer is nil")
    case len(connId) == 0:
        return nil, errors.New(dataCtx, errors.InvalidParameter, op, "connection id is empty")
    }
    remoteConn, err := out.Dial(ctrlCtx)
    if err != nil {
        return nil, err
    }

    return func(ctx context.Context) {
        connWg := new(sync.WaitGroup)
        connWg.Add(2)
        go func() {
            defer connWg.Done()
            _, _ = io.Copy(conn, remoteConn)
            _ = conn.Close()
            _ = remoteConn.Close()
        }()
        go func() {
            defer connWg.Done()
            _, _ = io.Copy(remoteConn, conn)
            _ = remoteConn.Close()
            _ = conn.Close()
        }()
        connWg.Wait()
    }, nil
}

